/**
 * Webhook notification handler — dispatches HTTP callbacks when order
 * lifecycle events occur.
 *
 * Integrates with the existing notification architecture by subscribing
 * to EventBus events, following the same pattern as EmailNotificationHandler
 * and NotificationService.
 *
 * Depends on:
 * - EventBus (event system) for receiving order events
 */

import type { EventBus } from '../events/event-bus.js';
import type {
  AppEvent,
  EventType,
  OrderCreatedEvent,
  OrderStatusChangedEvent,
} from '../events/event-types.js';
import { Logger } from '../utils/logger.js';

export interface WebhookRegistration {
  id: string;
  url: string;
  eventTypes: EventType[];
  secret?: string;
  createdAt: Date;
}

export interface WebhookDelivery {
  id: string;
  webhookId: string;
  url: string;
  eventType: EventType;
  payload: WebhookPayload;
  success: boolean;
  statusCode?: number;
  error?: string;
  deliveredAt: Date;
}

export interface WebhookPayload {
  eventType: EventType;
  timestamp: string;
  data: Record<string, unknown>;
}

export type WebhookSender = (
  url: string,
  payload: WebhookPayload,
  secret?: string,
) => Promise<{ success: boolean; statusCode?: number; error?: string }>;

/**
 * Default sender that simulates successful HTTP POST delivery (in-memory).
 */
const defaultSender: WebhookSender = async () => ({
  success: true,
  statusCode: 200,
});

let nextWebhookId = 1;
let nextDeliveryId = 1;

/**
 * Reset ID counters (useful for testing).
 */
export function resetWebhookIdCounters(): void {
  nextWebhookId = 1;
  nextDeliveryId = 1;
}

export class WebhookHandler {
  private logger = new Logger('WebhookHandler');
  private registrations: WebhookRegistration[] = [];
  private deliveries: WebhookDelivery[] = [];
  private sender: WebhookSender;

  constructor(
    private eventBus: EventBus,
    sender?: WebhookSender,
  ) {
    this.sender = sender ?? defaultSender;
    this.registerHandlers();
  }

  /**
   * Register event handlers for webhook dispatch triggers.
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', async (event) => {
      await this.dispatchWebhooks(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', async (event) => {
      await this.dispatchWebhooks(event);
    });
  }

  /**
   * Register a webhook URL for one or more event types.
   */
  registerWebhook(params: {
    url: string;
    eventTypes: EventType[];
    secret?: string;
  }): WebhookRegistration {
    const registration: WebhookRegistration = {
      id: `webhook-${String(nextWebhookId++).padStart(4, '0')}`,
      url: params.url,
      eventTypes: params.eventTypes,
      secret: params.secret,
      createdAt: new Date(),
    };

    this.registrations.push(registration);
    this.logger.info(
      `Registered webhook ${registration.id} for [${params.eventTypes.join(', ')}] -> ${params.url}`,
    );

    return registration;
  }

  /**
   * Unregister a webhook by ID.
   */
  unregisterWebhook(id: string): boolean {
    const index = this.registrations.findIndex((r) => r.id === id);
    if (index < 0) {
      return false;
    }
    this.registrations.splice(index, 1);
    this.logger.info(`Unregistered webhook ${id}`);
    return true;
  }

  /**
   * Get all registered webhooks.
   */
  getRegistrations(): WebhookRegistration[] {
    return [...this.registrations];
  }

  /**
   * Get registered webhooks for a specific event type.
   */
  getRegistrationsForEvent(eventType: EventType): WebhookRegistration[] {
    return this.registrations.filter((r) => r.eventTypes.includes(eventType));
  }

  /**
   * Get all delivery records.
   */
  getDeliveries(): WebhookDelivery[] {
    return [...this.deliveries];
  }

  /**
   * Get delivery records for a specific webhook.
   */
  getDeliveriesForWebhook(webhookId: string): WebhookDelivery[] {
    return this.deliveries.filter((d) => d.webhookId === webhookId);
  }

  /**
   * Get the count of registered webhooks.
   */
  getRegistrationCount(): number {
    return this.registrations.length;
  }

  /**
   * Get the count of deliveries.
   */
  getDeliveryCount(): number {
    return this.deliveries.length;
  }

  /**
   * Clear all registrations and deliveries (useful for testing).
   */
  clearAll(): void {
    this.registrations = [];
    this.deliveries = [];
  }

  /**
   * Dispatch webhooks to all registered URLs for the given event.
   */
  private async dispatchWebhooks(event: AppEvent): Promise<void> {
    const matching = this.registrations.filter((r) =>
      r.eventTypes.includes(event.type),
    );

    if (matching.length === 0) {
      return;
    }

    const payload = this.buildPayload(event);

    for (const registration of matching) {
      await this.deliver(registration, payload);
    }
  }

  /**
   * Deliver a payload to a single webhook registration.
   */
  private async deliver(
    registration: WebhookRegistration,
    payload: WebhookPayload,
  ): Promise<void> {
    this.logger.info(
      `Delivering ${payload.eventType} to webhook ${registration.id} (${registration.url})`,
    );

    const result = await this.sender(registration.url, payload, registration.secret);

    const delivery: WebhookDelivery = {
      id: `delivery-${String(nextDeliveryId++).padStart(4, '0')}`,
      webhookId: registration.id,
      url: registration.url,
      eventType: payload.eventType,
      payload,
      success: result.success,
      statusCode: result.statusCode,
      error: result.error,
      deliveredAt: new Date(),
    };

    this.deliveries.push(delivery);

    if (result.success) {
      this.logger.info(
        `Webhook ${registration.id} delivered successfully (${result.statusCode})`,
      );
    } else {
      this.logger.warn(
        `Webhook ${registration.id} delivery failed: ${result.error}`,
      );
    }
  }

  /**
   * Build the webhook payload from an event.
   */
  private buildPayload(event: AppEvent): WebhookPayload {
    switch (event.type) {
      case 'order:created':
        return {
          eventType: event.type,
          timestamp: event.timestamp.toISOString(),
          data: {
            orderId: event.order.id,
            userId: event.user.id,
            items: event.order.items,
            total: event.order.total,
            status: event.order.status,
          },
        };
      case 'order:status-changed':
        return {
          eventType: event.type,
          timestamp: event.timestamp.toISOString(),
          data: {
            orderId: event.order.id,
            previousStatus: event.previousStatus,
            newStatus: event.newStatus,
          },
        };
      default:
        return {
          eventType: event.type,
          timestamp: event.timestamp.toISOString(),
          data: {},
        };
    }
  }
}

