import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  WebhookHandler,
  resetWebhookIdCounters,
} from '../../src/notifications/webhook-handler.js';
import type { WebhookSender } from '../../src/notifications/webhook-handler.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
} from '../../src/events/event-types.js';

describe('WebhookHandler', () => {
  let eventBus: EventBus;
  let handler: WebhookHandler;

  beforeEach(() => {
    eventBus = new EventBus();
    handler = new WebhookHandler(eventBus);
    resetWebhookIdCounters();
  });

  const sampleOrderCreatedEvent: OrderCreatedEvent = {
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [
        { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
      ],
      total: 20,
      status: 'pending',
      createdAt: new Date('2026-01-01'),
      updatedAt: new Date('2026-01-01'),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date('2026-01-01'),
      updatedAt: new Date('2026-01-01'),
    },
    timestamp: new Date('2026-01-01T12:00:00Z'),
  };

  const sampleStatusChangedEvent: OrderStatusChangedEvent = {
    type: 'order:status-changed',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [],
      total: 20,
      status: 'confirmed',
      createdAt: new Date('2026-01-01'),
      updatedAt: new Date('2026-01-01'),
    },
    previousStatus: 'pending',
    newStatus: 'confirmed',
    timestamp: new Date('2026-01-01T13:00:00Z'),
  };

  describe('webhook registration', () => {
    it('should register a webhook and return registration with ID', () => {
      const reg = handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      expect(reg.id).toMatch(/^webhook-\d{4}$/);
      expect(reg.url).toBe('https://example.com/hook');
      expect(reg.eventTypes).toEqual(['order:created']);
      expect(reg.createdAt).toBeInstanceOf(Date);
    });

    it('should register a webhook with a secret', () => {
      const reg = handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
        secret: 'my-secret',
      });

      expect(reg.secret).toBe('my-secret');
    });

    it('should register webhooks for multiple event types', () => {
      const reg = handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created', 'order:status-changed'],
      });

      expect(reg.eventTypes).toEqual(['order:created', 'order:status-changed']);
    });

    it('should return registration count', () => {
      expect(handler.getRegistrationCount()).toBe(0);

      handler.registerWebhook({
        url: 'https://example.com/hook1',
        eventTypes: ['order:created'],
      });
      handler.registerWebhook({
        url: 'https://example.com/hook2',
        eventTypes: ['order:status-changed'],
      });

      expect(handler.getRegistrationCount()).toBe(2);
    });

    it('should get all registrations', () => {
      handler.registerWebhook({
        url: 'https://example.com/hook1',
        eventTypes: ['order:created'],
      });
      handler.registerWebhook({
        url: 'https://example.com/hook2',
        eventTypes: ['order:status-changed'],
      });

      const regs = handler.getRegistrations();
      expect(regs).toHaveLength(2);
      expect(regs[0]?.url).toBe('https://example.com/hook1');
      expect(regs[1]?.url).toBe('https://example.com/hook2');
    });

    it('should get registrations for a specific event type', () => {
      handler.registerWebhook({
        url: 'https://example.com/hook1',
        eventTypes: ['order:created'],
      });
      handler.registerWebhook({
        url: 'https://example.com/hook2',
        eventTypes: ['order:status-changed'],
      });
      handler.registerWebhook({
        url: 'https://example.com/hook3',
        eventTypes: ['order:created', 'order:status-changed'],
      });

      const createdRegs = handler.getRegistrationsForEvent('order:created');
      expect(createdRegs).toHaveLength(2);

      const statusRegs = handler.getRegistrationsForEvent('order:status-changed');
      expect(statusRegs).toHaveLength(2);
    });

    it('should unregister a webhook by ID', () => {
      const reg = handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      expect(handler.unregisterWebhook(reg.id)).toBe(true);
      expect(handler.getRegistrationCount()).toBe(0);
    });

    it('should return false when unregistering non-existent webhook', () => {
      expect(handler.unregisterWebhook('webhook-9999')).toBe(false);
    });
  });

  describe('webhook delivery on order:created', () => {
    it('should deliver webhook when order:created fires', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      await eventBus.emit(sampleOrderCreatedEvent);

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.success).toBe(true);
      expect(deliveries[0]?.eventType).toBe('order:created');
      expect(deliveries[0]?.url).toBe('https://example.com/hook');
    });

    it('should include correct payload for order:created', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      await eventBus.emit(sampleOrderCreatedEvent);

      const delivery = handler.getDeliveries()[0]!;
      expect(delivery.payload.eventType).toBe('order:created');
      expect(delivery.payload.timestamp).toBe('2026-01-01T12:00:00.000Z');
      expect(delivery.payload.data).toEqual({
        orderId: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
        total: 20,
        status: 'pending',
      });
    });

    it('should not deliver to webhooks registered for other event types', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:status-changed'],
      });

      await eventBus.emit(sampleOrderCreatedEvent);

      expect(handler.getDeliveryCount()).toBe(0);
    });
  });

  describe('webhook delivery on order:status-changed', () => {
    it('should deliver webhook when order:status-changed fires', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:status-changed'],
      });

      await eventBus.emit(sampleStatusChangedEvent);

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.success).toBe(true);
      expect(deliveries[0]?.eventType).toBe('order:status-changed');
    });

    it('should include correct payload for order:status-changed', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:status-changed'],
      });

      await eventBus.emit(sampleStatusChangedEvent);

      const delivery = handler.getDeliveries()[0]!;
      expect(delivery.payload.data).toEqual({
        orderId: 'order-1',
        previousStatus: 'pending',
        newStatus: 'confirmed',
      });
    });
  });

  describe('multiple webhooks and deliveries', () => {
    it('should deliver to multiple webhooks for the same event', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook1',
        eventTypes: ['order:created'],
      });
      handler.registerWebhook({
        url: 'https://example.com/hook2',
        eventTypes: ['order:created'],
      });

      await eventBus.emit(sampleOrderCreatedEvent);

      expect(handler.getDeliveryCount()).toBe(2);
      const deliveries = handler.getDeliveries();
      expect(deliveries[0]?.url).toBe('https://example.com/hook1');
      expect(deliveries[1]?.url).toBe('https://example.com/hook2');
    });

    it('should deliver to webhook registered for multiple event types', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created', 'order:status-changed'],
      });

      await eventBus.emit(sampleOrderCreatedEvent);
      await eventBus.emit(sampleStatusChangedEvent);

      expect(handler.getDeliveryCount()).toBe(2);
    });

    it('should get deliveries for a specific webhook', async () => {
      const reg1 = handler.registerWebhook({
        url: 'https://example.com/hook1',
        eventTypes: ['order:created'],
      });
      handler.registerWebhook({
        url: 'https://example.com/hook2',
        eventTypes: ['order:created'],
      });

      await eventBus.emit(sampleOrderCreatedEvent);

      const deliveries = handler.getDeliveriesForWebhook(reg1.id);
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.url).toBe('https://example.com/hook1');
    });
  });

  describe('delivery failures', () => {
    it('should record failed deliveries', async () => {
      const failSender: WebhookSender = async () => ({
        success: false,
        statusCode: 500,
        error: 'Internal Server Error',
      });

      const failHandler = new WebhookHandler(eventBus, failSender);
      failHandler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      await eventBus.emit(sampleOrderCreatedEvent);

      const deliveries = failHandler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.success).toBe(false);
      expect(deliveries[0]?.statusCode).toBe(500);
      expect(deliveries[0]?.error).toBe('Internal Server Error');
    });
  });

  describe('custom sender', () => {
    it('should pass secret to sender', async () => {
      let receivedSecret: string | undefined;
      const spySender: WebhookSender = async (_url, _payload, secret) => {
        receivedSecret = secret;
        return { success: true, statusCode: 200 };
      };

      const spyHandler = new WebhookHandler(eventBus, spySender);
      spyHandler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
        secret: 'top-secret',
      });

      await eventBus.emit(sampleOrderCreatedEvent);

      expect(receivedSecret).toBe('top-secret');
    });

    it('should pass correct URL and payload to sender', async () => {
      let receivedUrl: string | undefined;
      let receivedPayload: unknown;
      const spySender: WebhookSender = async (url, payload) => {
        receivedUrl = url;
        receivedPayload = payload;
        return { success: true, statusCode: 200 };
      };

      const spyHandler = new WebhookHandler(eventBus, spySender);
      spyHandler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      await eventBus.emit(sampleOrderCreatedEvent);

      expect(receivedUrl).toBe('https://example.com/hook');
      expect(receivedPayload).toHaveProperty('eventType', 'order:created');
    });
  });

  describe('cleanup', () => {
    it('should clear all registrations and deliveries', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      await eventBus.emit(sampleOrderCreatedEvent);

      handler.clearAll();
      expect(handler.getRegistrationCount()).toBe(0);
      expect(handler.getDeliveryCount()).toBe(0);
    });
  });

  describe('coexistence with other handlers', () => {
    it('should work alongside EmailNotificationHandler on same EventBus', async () => {
      const { EmailNotificationHandler } = await import(
        '../../src/notifications/email-handler.js'
      );
      const emailHandler = new EmailNotificationHandler(eventBus);

      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      await eventBus.emit(sampleOrderCreatedEvent);

      expect(handler.getDeliveryCount()).toBe(1);
      expect(emailHandler.getSentEmailCount()).toBe(1);
    });

    it('should work alongside NotificationService on same EventBus', async () => {
      const { NotificationService } = await import(
        '../../src/services/notification.service.js'
      );
      const notifService = new NotificationService(eventBus);

      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      await eventBus.emit(sampleOrderCreatedEvent);

      expect(handler.getDeliveryCount()).toBe(1);
      expect(notifService.getNotificationCount()).toBe(1);
    });
  });
});

