+
+  /**
+   * Get all registered webhooks.
+   */
+  getRegistrations(): WebhookRegistration[] {
+    return [...this.registrations];
+  }
+
+  /**
+   * Get registered webhooks for a specific event type.
+   */
+  getRegistrationsForEvent(eventType: EventType): WebhookRegistration[] {
+    return this.registrations.filter((r) => r.eventTypes.includes(eventType));
+  }
+
+  /**
+   * Get all delivery records.
+   */
+  getDeliveries(): WebhookDelivery[] {
+    return [...this.deliveries];
+  }
+
+  /**
+   * Get delivery records for a specific webhook.
+   */
+  getDeliveriesForWebhook(webhookId: string): WebhookDelivery[] {
+    return this.deliveries.filter((d) => d.webhookId === webhookId);
+  }
+
+  /**
+   * Get the count of registered webhooks.
+   */
+  getRegistrationCount(): number {
+    return this.registrations.length;
+  }
+
+  /**
+   * Get the count of deliveries.
+   */
+  getDeliveryCount(): number {
+    return this.deliveries.length;
+  }
+
+  /**
+   * Clear all registrations and deliveries (useful for testing).
+   */
+  clearAll(): void {
+    this.registrations = [];
+    this.deliveries = [];
+  }
+
+  /**
+   * Dispatch webhooks to all registered URLs for the given event.
+   */
+  private async dispatchWebhooks(event: AppEvent): Promise<void> {
+    const matching = this.registrations.filter((r) =>
+      r.eventTypes.includes(event.type),
+    );
+
+    if (matching.length === 0) {
+      return;
+    }
+
+    const payload = this.buildPayload(event);
+
+    for (const registration of matching) {
+      await this.deliver(registration, payload);
+    }
+  }
+
+  /**
+   * Deliver a payload to a single webhook registration.
+   */
+  private async deliver(
+    registration: WebhookRegistration,
+    payload: WebhookPayload,
+  ): Promise<void> {
+    this.logger.info(
+      `Delivering ${payload.eventType} to webhook ${registration.id} (${registration.url})`,
+    );
+
+    const result = await this.sender(registration.url, payload, registration.secret);
+
+    const delivery: WebhookDelivery = {
+      id: `delivery-${String(nextDeliveryId++).padStart(4, '0')}`,
+      webhookId: registration.id,
+      url: registration.url,
+      eventType: payload.eventType,
+      payload,
+      success: result.success,
+      statusCode: result.statusCode,
+      error: result.error,
+      deliveredAt: new Date(),
+    };
+
+    this.deliveries.push(delivery);
+
+    if (result.success) {
+      this.logger.info(
+        `Webhook ${registration.id} delivered successfully (${result.statusCode})`,
+      );
+    } else {
+      this.logger.warn(
+        `Webhook ${registration.id} delivery failed: ${result.error}`,
+      );
+    }
+  }
+
+  /**
+   * Build the webhook payload from an event.
+   */
+  private buildPayload(event: AppEvent): WebhookPayload {
+    switch (event.type) {
+      case 'order:created':
+        return {
+          eventType: event.type,
+          timestamp: event.timestamp.toISOString(),
+          data: {
+            orderId: event.order.id,
+            userId: event.user.id,
+            items: event.order.items,
+            total: event.order.total,
+            status: event.order.status,
+          },
+        };
+      case 'order:status-changed':
+        return {
+          eventType: event.type,
+          timestamp: event.timestamp.toISOString(),
+          data: {
+            orderId: event.order.id,
+            previousStatus: event.previousStatus,
+            newStatus: event.newStatus,
+          },
+        };
+      default:
+        return {
+          eventType: event.type,
+          timestamp: event.timestamp.toISOString(),
+          data: {},
+        };
+    }
+  }
+}

